# Generated by build_cd38_external_tool_runbook.py
# Run only the CD38 external-tool actions that are still missing from the action plan.
$ErrorActionPreference = 'Stop'
$PackageRoot = Split-Path -Parent $MyInvocation.MyCommand.Path

function Require-Command {
    param([string]$Name)
    if (-not (Get-Command $Name -ErrorAction SilentlyContinue)) {
        throw "Required command not found in PATH: $Name"
    }
}

function Require-File {
    param([string]$Path)
    if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) {
        throw "Required input file not found: $Path"
    }
}

Require-Command 'prank'
Require-Command 'fpocket'

Write-Host "Running 4 CD38 external-tool action(s)."

Write-Host "[1/4] 3ROP fpocket"
$RunDir = Join-Path $PackageRoot "fpocket_runs\3ROP"
$RunPdb = Join-Path $RunDir "3ROP.pdb"
Require-File $RunPdb
Push-Location $RunDir
try {
    fpocket -f "3ROP.pdb"
} finally {
    Pop-Location
}

Write-Host "[2/4] 4OGW fpocket"
$RunDir = Join-Path $PackageRoot "fpocket_runs\4OGW"
$RunPdb = Join-Path $RunDir "4OGW.pdb"
Require-File $RunPdb
Push-Location $RunDir
try {
    fpocket -f "4OGW.pdb"
} finally {
    Pop-Location
}

Write-Host "[3/4] 3F6Y fpocket"
$RunDir = Join-Path $PackageRoot "fpocket_runs\3F6Y"
$RunPdb = Join-Path $RunDir "3F6Y.pdb"
Require-File $RunPdb
Push-Location $RunDir
try {
    fpocket -f "3F6Y.pdb"
} finally {
    Pop-Location
}

Write-Host "[4/4] 3F6Y p2rank"
$PdbPath = Join-Path $PackageRoot "pdbs\3F6Y.pdb"
$OutDir = Join-Path $PackageRoot "p2rank_outputs\3F6Y"
$null = New-Item -ItemType Directory -Force -Path $OutDir
Require-File $PdbPath
prank predict -f $PdbPath -o $OutDir

Write-Host 'External-tool actions finished.'
Write-Host 'Return the whole package folder or zip it, then import/finalize in the original ML project.'
